"/users/{userId}": {
"get": {
"operationId": "get-user",
"x-zuplo-route": {
"corsPolicy": "anything-goes",
"handler": {
"export": "urlForwardHandler",
"module": "$import(@zuplo/runtime)",
"options": {
"baseUrl": "https://api.example.com"
}
},
"policies": {
"inbound": ["api-key-inbound", "rate-limit-inbound"]
}
}
}
}
}
